import {
  html,
  customElement,
  state,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbModalBaseElement } from "@umbraco-cms/backoffice/modal";
import { UmbTemporaryFileRepository } from "@umbraco-cms/backoffice/temporary-file";
import { FormService } from "@umbraco-forms/generated";
import { UMB_ACTION_EVENT_CONTEXT } from "@umbraco-cms/backoffice/action";
import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import { UMB_NOTIFICATION_CONTEXT } from "@umbraco-cms/backoffice/notification";
import { FORMS_FORM_ENTITY_TYPE } from "../../../entities.js";
import type { FormsFormImportModalData } from "./index.js";
import { UmbRequestReloadChildrenOfEntityEvent } from "@umbraco-cms/backoffice/entity-action";
import { UmbInputUploadFieldElement } from "@umbraco-cms/backoffice/media";

// TODO => sync tree after import. It was working briefly, then stopped. Shrugs.

const elementName = "forms-form-import-modal";

@customElement(elementName)
export class FormsFormImportModalElement extends UmbModalBaseElement<FormsFormImportModalData> {
  #temporaryFileRepository = new UmbTemporaryFileRepository(this);

  @state()
  private _temporaryFileKey?: string | null | undefined;

  async #import() {
    if (!this._temporaryFileKey) throw new Error("file key is missing");

    const { data, error } = await tryExecuteAndNotify(
      this,
      FormService.postFormImport({
        requestBody: {
          fileKey: this._temporaryFileKey,
          folderId: this.data?.unique,
        },
      })
    );

    if (!data || error) {
      const notificationContext = await this.getContext(
        UMB_NOTIFICATION_CONTEXT
      );
      notificationContext.peek("danger", {
        data: { message: "Unable to import form." },
      });

      this._rejectModal();
    }

    const event = new UmbRequestReloadChildrenOfEntityEvent({
      entityType: FORMS_FORM_ENTITY_TYPE,
      unique: null,
    });

    const eventContext = await this.getContext(UMB_ACTION_EVENT_CONTEXT);
    eventContext.dispatchEvent(event);

    history.pushState(
      {},
      "",
      `/umbraco/section/forms/workspace/form/edit/${data}`
    );

    this._submitModal();
  }

  async #handleFileSelection(event: CustomEvent) {
    const target = event.target as unknown as UmbInputUploadFieldElement;
    const temporaryFileKey = target.value.temporaryFileId;

    // delete previous if no value - file was removed
    if (!temporaryFileKey && this._temporaryFileKey) {
      await this.#temporaryFileRepository.delete(this._temporaryFileKey);
    }

    this._temporaryFileKey = temporaryFileKey;
  }

  render() {
    return html`
      <umb-body-layout .headline=${this.localize.term("general_import")}>
        <uui-box
          ><p>${this.localize.term("formImport_importInstruction1")}</p>
          <umb-input-upload-field
            @change=${this.#handleFileSelection}
            ?multiple=${false}
            .fileExtensions=${["json"]}
            .keys=${this._temporaryFileKey ? [this._temporaryFileKey] : []}
          ></umb-input-upload-field>
          <p>${this.localize.term("formImport_importInstruction2")}</p></uui-box
        >
        <uui-button
          slot="actions"
          label=${this.localize.term("general_cancel")}
          @click="${this._rejectModal}"
        ></uui-button>
        <uui-button
          slot="actions"
          label=${this.localize.term("general_import")}
          look="primary"
          color="positive"
          @click=${this.#import}
        ></uui-button>
      </umb-body-layout>
    `;
  }
}

export default FormsFormImportModalElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsFormImportModalElement;
  }
}
